import { ethers } from 'ethers';

// Initialize provider and signer
const provider = new ethers.providers.Web3Provider(window.ethereum);
const signer = provider.getSigner();

// Function to interact with smart contract
async function interactWithContract(contractAddress, abi, functionName, ...args) {
  try {
    // Request account access if needed
    await provider.send("eth_requestAccounts", []);
    
    // Create contract instance
    const contract = new ethers.Contract(contractAddress, abi, signer);
    
    // Estimate gas limit
    const gasLimit = await contract.estimateGas[functionName](...args);
    
    // Send transaction
    const tx = await contract[functionName](...args, { gasLimit });
    
    // Wait for transaction to be mined
    await tx.wait();
    
    console.log('Transaction successful:', tx);
  } catch (error) {
    console.error('Error interacting with contract:', error);
  }
}

// Example usage
document.getElementById('submitBtn').addEventListener('click', async () => {
  const contractAddress = document.getElementById('contractAddress').value;
  const abi = JSON.parse(document.getElementById('contractAbi').value);
  const functionName = document.getElementById('functionName').value;
  const args = JSON.parse(document.getElementById('functionArgs').value);
  
  await interactWithContract(contractAddress, abi, functionName, ...args);
});